import CustomCarousel from './components/CustomCarousel';
import VideoCardContainer from './components/CustomVideoCardContainer';

import ScrollListener from './components/ScrollListener';

import React, { useState} from 'react';


import { images, videos, largeLayers, mediumLayers, smallLayers } from './constants';

import GameCard from './components/CustomGameCard';

import CustomSection from './components/CustomSection';
import CustomParallax from './components/CustomParallax';
import CustomFooterButtons from './components/CustomFooterButtons';

function App() {

  const [scrollPercentage, setScrollPercentage] = useState(0);

  const handleScroll = (percentage) => {
    setScrollPercentage(percentage);
  };

  return (
    <div className="App">
    
      {/*Inicializamos el componente que lleva el control del porcentaje de scroll*/}
      <ScrollListener onScroll={handleScroll} />

      {/*Header vacio de momento no lo vamos a utilizar.*/}
      <header/>
      
      <section id='section-0' />

      <CustomParallax
        scrollPercentage={scrollPercentage}
        largeLayers={largeLayers}
        mediumLayers={mediumLayers}
        smallLayers={smallLayers}
      />
      

    
      <VideoCardContainer videos={videos} />
      <section id='section-1' />
   

      <section id='section-2' />
      
      <CustomSection children={
        <GameCard
          gameTitle={"Sediento"}
          gameEmbed={"./Sediento/game.html"}
          maxWidth={600}
        />
      } />

      <section id='section-3' />
      

      <section id='section-4' />
      <CustomCarousel images={images} />


      <footer>
        <CustomFooterButtons scrollPercentage={scrollPercentage}/>
        {/*<ScrollProgressBar scrollPercentage={scrollPercentage} />*/}
      </footer>
    </div>
  );
}

export default App;
